selector_to_html = {"a[href=\"#id1\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4 </span><i class=\"fa fa-rocket\"></i> Quick Start<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p>In this chapter, we demonstrate how to use <strong>AimDK</strong> for secondary development on the AgiBot X2 by walking through <strong>building and running SDK sample programs</strong> and <strong>developing combined robot control programs</strong>.</p>", "a[href=\"run_example.html#id1\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.5.1 </span>Get the Robot\u2019s Current State<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>Sample Output</strong></p><p>If you see the following output, you have successfully connected to the robot and retrieved its current Locomotion Mode.</p>", "a[href=\"prerequisites.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.1 </span>Read the user guide to familiarize yourself with relevant terminology and safety precautions.<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"code_sample.html#id8\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.6.4 </span>Build and Run<a class=\"headerlink\" href=\"#id8\" title=\"Link to this heading\">\uf0c1</a></h2><h3>Build the Project<a class=\"headerlink\" href=\"#id9\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"code_sample.html#id11\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.6.5 </span>Code Walkthrough<a class=\"headerlink\" href=\"#id11\" title=\"Link to this heading\">\uf0c1</a></h2><h3>Robot Control Class<a class=\"headerlink\" href=\"#id12\" title=\"Link to this heading\">\uf0c1</a></h3><p>The <code class=\"docutils literal notranslate\"><span class=\"pre\">ActionSequenceDemo</span></code> class is the core of robot control and provides the following capabilities:</p>", "a[href=\"run_example.html#id2\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.5.2 </span>Make the Robot Wave<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2><p>Switch the robot to <span class=\"highlight-target\">Stable Standing Mode (Force-Control Stand)</span>. Please refer to the state transition diagram.</p>", "a[href=\"code_sample.html#sdk\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.6.2 </span>Add the Example to the Existing SDK Workspace<a class=\"headerlink\" href=\"#sdk\" title=\"Link to this heading\">\uf0c1</a></h2><p>We will add a new example program to the existing SDK workspace, which allows you to:</p>", "a[href=\"code_sample.html#id13\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.6.6 </span>Extensions and Optimization<a class=\"headerlink\" href=\"#id13\" title=\"Link to this heading\">\uf0c1</a></h2><h3>Add More Actions and Interactions<a class=\"headerlink\" href=\"#id14\" title=\"Link to this heading\">\uf0c1</a></h3><p>You can extend the existing code to add more robot actions and interaction features, for example:</p>", "a[href=\"code_sample.html#id4\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.6.3 </span>Write the Control Code<a class=\"headerlink\" href=\"#id4\" title=\"Link to this heading\">\uf0c1</a></h2><h3>Create the Robot Control Class<a class=\"headerlink\" href=\"#id5\" title=\"Link to this heading\">\uf0c1</a></h3><p>In <code class=\"docutils literal notranslate\"><span class=\"pre\">src/py_examples/py_examples/action_sequence_demo.py</span></code>, add the following code:</p>", "a[href=\"prerequisites.html#id2\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.2 </span>Complete the basic system configuration<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h1><p>And SDK example dependencies:</p>", "a[href=\"code_sample.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.6 </span>Code Implementation<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>In this section, you will develop a simple robot control program that makes robot X2 perform a sequence of hand motions and speech playback.</strong></p>", "a[href=\"prerequisites.html#id3\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.3 </span>Network connection<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h1><p>The AgiBot X2 Ultra supports multiple network access methods to connect to the onboard system:</p><p><strong>(1) Direct wired connection via the rear Ethernet port</strong> \u2014 Connect a network cable between the robot\u2019s <a class=\"reference internal\" href=\"../about_agibot_X2/SDK_interface.html#img-x2-sdk-interface\"><span class=\"std std-ref\">SDK development Ethernet port</span></a> and the host PC.</p>", "a[href=\"run_example.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.5 </span>Run an Example Program<a class=\"headerlink\" href=\"#aimdk-run\" title=\"Link to this heading\">\uf0c1</a></h1><h2><span class=\"section-number\">4.5.1 </span>Get the Robot\u2019s Current State<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>Sample Output</strong></p><p>If you see the following output, you have successfully connected to the robot and retrieved its current Locomotion Mode.</p>", "a[href=\"code_sample.html#id18\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.6.7 </span>Troubleshooting<a class=\"headerlink\" href=\"#id18\" title=\"Link to this heading\">\uf0c1</a></h2><p>First, check the <a class=\"reference internal\" href=\"../faq/index.html#faq\"><span class=\"std std-ref\"> FAQ</span></a> section. If the issue is still not resolved, consider contacting AgiBot X2 technical support.</p>", "a[href=\"code_sample.html#id20\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.6.9 </span>Summary<a class=\"headerlink\" href=\"#id20\" title=\"Link to this heading\">\uf0c1</a></h2><p>By now, you have learned how to:</p>", "a[href=\"code_sample.html#id2\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.6.1 </span>Project Overview<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2><p>In this project, we will develop a Python program that uses ROS 2 interfaces to control robot X2 to perform the following action sequence:</p>", "a[href=\"code_sample.html#id19\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.6.8 </span>Next Steps<a class=\"headerlink\" href=\"#id19\" title=\"Link to this heading\">\uf0c1</a></h2><p>After completing this section, you can:</p>", "a[href=\"prerequisites.html#aimdk-build\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4.4 </span>Environment installation and configuration<a class=\"headerlink\" href=\"#aimdk-build\" title=\"Link to this heading\">\uf0c1</a></h1><p>Place the SDK into the target environment and extract it.</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false, theme: 'material', duration: [300, 200], delay: [200, 100],

            });
        };
    };
    console.log("tippy tips loaded!");
};
